        stack: [{ name: "Ada / simple IVR", role: "Basic Automation", why: "After-hours self-service for payments, outage reporting, and account balance. Keep daytime interactions human — community utility customers expect to reach a person they might see at the hardware store.", href: "/vendors/iva" }],
