        stack: [{ name: "NISC", role: "Cooperative CIS", why: "Purpose-built for electric cooperatives and municipal utilities. Billing, accounting, and customer service on one platform. Designed for the scale and governance model of community-owned utilities.", href: "/vendors" }, { name: "Cayenta (Harris)", role: "Municipal CIS", why: "Utility billing and customer service for municipal utilities. Handles the combined utility billing (electric + water + sewer + trash) common in municipal operations.", href: "/vendors" }],
