        stack: [{ name: "Custom DER portal", role: "Interconnection Tracking", why: "Most utilities build custom interconnection portals because no off-the-shelf product handles the complexity of engineering review, inspection scheduling, and meter exchange coordination. The portal IS the CX for solar customers.", href: "/vendors" }, { name: "Bidgely", role: "Energy Analytics", why: "Disaggregated energy analysis showing DER customers their solar production, battery performance, grid consumption, and net metering credits. Turns 'why is my bill still high?' into a self-service discovery.", href: "/vendors" }],
