        stack: [{ name: "Five9", role: "CCaaS", why: "Strong for competitive retail operations with mixed inbound/outbound. Sales dialer for acquisition combined with service routing for existing customers. Good for 50-300 agent operations.", href: "/vendors/five9" }],
