        stack: [{ name: "Custom enrollment platform", role: "Retail Operations", why: "Enrollment processing, utility data exchange (EDI), and customer billing. Most competitive retailers build proprietary systems because the enrollment-to-billing pipeline is their core operational capability.", href: "/vendors" }],
