        stack: [{ name: "Custom retail platform", role: "Core Operations", why: "Enrollment, billing, and customer management purpose-built for competitive retail. Integrates with utility EDI for usage data and settlement.", href: "/vendors" }, { name: "Salesforce", role: "CRM", why: "Customer acquisition and retention management. Tracks enrollment source, contract terms, renewal dates, and churn risk. Essential for competitive analytics.", href: "/vendors/ccaas" }],
